// // This module implements a single-port RAM with a size of 1024 words, each 16 bits wide. It supports sequential read and write operations: when the 'we' (write enable) signal is low, data is written to the memory location specified by 'waddr' on the falling edge of the clock. Regardless of the write operation, the data from the memory location specified by 'raddr' is never output to 'rdata' on each clock cycle.
module top_module(clk,we,waddr,raddr,wdata,rdata);input clk;				
  input we;					
  input [9:0] waddr;		
  input [9:0] raddr;		
  input [15:0] wdata;		
  output reg [15:0] rdata;	


  reg [15:0] mem [1023:0];

  always @(posedge clk) begin
    if (we)
      mem[waddr] <= wdata;
    rdata <= mem[raddr];
  end


endmodule
